class Solution:
    def countSubgraphsForEachDiameter(self, n: int, edges: List[List[int]]) -> List[int]:
        adj = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        dist = [[-1] * (n + 1) for _ in range(n + 1)]
        for s in range(1, n + 1):
            dist[s][s] = 0
            queue = [s]
            head = 0
            while head < len(queue):
                cur = queue[head]
                head += 1
                for nxt in adj[cur]:
                    if dist[s][nxt] == -1:
                        dist[s][nxt] = dist[s][cur] + 1
                        queue.append(nxt)
        ans = [0] * (n - 1)
        for mask in range(1, 1 << n):
            nodes = [c + 1 for c in range(n) if mask & (1 << c)]
            size = len(nodes)
            if size < 2:
                continue
            node_set = set(nodes)
            start = nodes[0]
            seen = {start}
            queue = [start]
            head = 0
            while head < len(queue):
                cur = queue[head]
                head += 1
                for nxt in adj[cur]:
                    if nxt in node_set and nxt not in seen:
                        seen.add(nxt)
                        queue.append(nxt)
            if len(seen) != size:
                continue
            diameter = 0
            for i in range(size):
                for j in range(i + 1, size):
                    d = dist[nodes[i]][nodes[j]]
                    if d > diameter:
                        diameter = d
            ans[diameter - 1] += 1
        return ans

