class Solution:
    def countSubgraphsForEachDiameter(self, n: int, edges: List[List[int]]) -> List[int]:
        adj = [[] for _ in range(n + 1)]
        edge_set = set()
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
            edge_set.add((min(u, v), max(u, v)))
        ans = [0] * (n - 1)
        def bfs(start, node_set):
            dist = {start: 0}
            queue = [start]
            head = 0
            while head < len(queue):
                cur = queue[head]
                head += 1
                for nxt in adj[cur]:
                    if nxt in node_set and nxt not in dist:
                        dist[nxt] = dist[cur] + 1
                        queue.append(nxt)
            return dist
        for mask in range(1, 1 << n):
            nodes = [c + 1 for c in range(n) if mask & (1 << c)]
            size = len(nodes)
            if size < 2:
                continue
            node_set = set(nodes)
            cnt = 0
            for (u, v) in edge_set:
                if u in node_set and v in node_set:
                    cnt += 1
            if cnt != size - 1:
                continue
            d1 = bfs(nodes[0], node_set)
            far = max(d1, key=d1.get)
            d2 = bfs(far, node_set)
            diameter = max(d2.values())
            ans[diameter - 1] += 1
        return ans

