var countSubgraphsForEachDiameter = function(n, edges) {
    const adj = Array.from({length: n + 1}, () => []);
    const edgeSet = new Set();
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
        const key = Math.min(u, v) * 100 + Math.max(u, v);
        edgeSet.add(key);
    }
    const ans = new Array(n - 1).fill(0);
    const bfs = (start, nodeSet) => {
        const dist = new Map([[start, 0]]);
        const queue = [start];
        let head = 0;
        while (head < queue.length) {
            const cur = queue[head++];
            for (const nxt of adj[cur]) {
                if (nodeSet.has(nxt) && !dist.has(nxt)) {
                    dist.set(nxt, dist.get(cur) + 1);
                    queue.push(nxt);
                }
            }
        }
        return dist;
    };
    for (let mask = 1; mask < (1 << n); mask++) {
        const nodes = [];
        for (let c = 0; c < n; c++) {
            if (mask & (1 << c)) nodes.push(c + 1);
        }
        const size = nodes.length;
        if (size < 2) continue;
        const nodeSet = new Set(nodes);
        let cnt = 0;
        for (const key of edgeSet) {
            const u = Math.floor(key / 100), v = key % 100;
            if (nodeSet.has(u) && nodeSet.has(v)) cnt++;
        }
        if (cnt !== size - 1) continue;
        const d1 = bfs(nodes[0], nodeSet);
        let far = nodes[0], best = -1;
        for (const [node, d] of d1) {
            if (d > best) { best = d; far = node; }
        }
        const d2 = bfs(far, nodeSet);
        let diameter = 0;
        for (const d of d2.values()) {
            if (d > diameter) diameter = d;
        }
        ans[diameter - 1]++;
    }
    return ans;
};
